import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { BehaviorSubject, Observable } from 'rxjs';
import { tap, catchError } from 'rxjs/operators';
import { throwError } from 'rxjs';
import { ParkaddaLoginRequest, ParkaddaLoginResponse } from '../models/parkadda.models';

/**
 * Parkadda Authentication Service
 * Handles login and token management for Parkadda API
 */
@Injectable({
  providedIn: 'root'
})
export class ParkaddaAuthService {
  private readonly baseUrl = '/api';
  private parkaddaTokenSubject = new BehaviorSubject<string | null>(this.getParkaddaToken());
  public parkaddaToken$ = this.parkaddaTokenSubject.asObservable();

  private parkaddaMobileSubject = new BehaviorSubject<string | null>(this.getParkaddaMobile());
  public parkaddaMobile$ = this.parkaddaMobileSubject.asObservable();

  constructor(private http: HttpClient) {}

  /**
   * Admin login for Parkadda - obtains Bearer token
   * @param mobile Admin mobile number
   * @param password Admin password
   * @returns Observable with access token
   */
  adminLogin(mobile: string, password: string): Observable<ParkaddaLoginResponse> {
    const loginRequest: ParkaddaLoginRequest = { mobile, password };
    return this.http.post<ParkaddaLoginResponse>(
      `${this.baseUrl}/user/admin-login/`,
      loginRequest
    ).pipe(
      tap((response: ParkaddaLoginResponse) => {
        // Store token and mobile for future requests
        this.setParkaddaToken(response.access_token);
        this.setParkaddaMobile(mobile);
      }),
      catchError(error => {
        console.error('Parkadda admin login failed:', error);
        return throwError(() => new Error('Admin login failed. Please check credentials.'));
      })
    );
  }

  /**
   * Get stored Parkadda token
   */
  getParkaddaToken(): string | null {
    return localStorage.getItem('parkadda_token');
  }

  /**
   * Set Parkadda token in localStorage
   */
  private setParkaddaToken(token: string): void {
    localStorage.setItem('parkadda_token', token);
    this.parkaddaTokenSubject.next(token);
  }

  /**
   * Get stored Parkadda mobile
   */
  getParkaddaMobile(): string | null {
    return localStorage.getItem('parkadda_mobile');
  }

  /**
   * Set Parkadda mobile in localStorage
   */
  private setParkaddaMobile(mobile: string): void {
    localStorage.setItem('parkadda_mobile', mobile);
    this.parkaddaMobileSubject.next(mobile);
  }

  /**
   * Check if user is logged into Parkadda
   */
  isParkaddaLoggedIn(): boolean {
    return !!this.getParkaddaToken();
  }

  /**
   * Check if user is authenticated (alias for isParkaddaLoggedIn)
   */
  isParkaddaAuthenticated(): boolean {
    return this.isParkaddaLoggedIn();
  }

  /**
   * Logout from Parkadda
   */
  logout(): void {
    localStorage.removeItem('parkadda_token');
    localStorage.removeItem('parkadda_mobile');
    this.parkaddaTokenSubject.next(null);
    this.parkaddaMobileSubject.next(null);
  }

  /**
   * Logout from Parkadda (alias)
   */
  parkaddaLogout(): void {
    this.logout();
  }
}
